}.darma-loader-darma-custom-400:before {animation: darma-loader-darma-custom-400-l9 1s infinite;
  transform: perspective(300px) translateZ(0px)}@keyframes darma-loader-darma-custom-400-l9 {to {transform: perspective(300px) translateZ(100px);
  opacity:0}}

